using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>() — strongly-typed metadata retrieval ---

var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> => Type: {personInfo.Type.Name}, Props: {personInfo.Properties.Count}");

// Use it to serialize
string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>() — probe without throwing ---

// With the default reflection resolver, any public type resolves:
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded — {found!.Type.Name}");
}

// Build options that use a *source-gen* context which only knows about Person.
// Asking for int[] will fail — but TryGetTypeInfo won't throw.
var limited = new JsonSerializerOptions { TypeInfoResolver = PersonOnlyContext.Default };

if (limited.TryGetTypeInfo<int[]>(out JsonTypeInfo<int[]>? arrayInfo))
{
    Console.WriteLine($"TryGetTypeInfo<int[]> succeeded — {arrayInfo!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<int[]> returned false — no metadata available (no exception thrown)");
}

// -- Types ---------------------------------------------------------------

public record Person(string Name, int Age);

[JsonSerializable(typeof(Person))]
public partial class PersonOnlyContext : JsonSerializerContext;

